#!/usr/bin/env python3
"""Generate Phase 9 eval dataset (150 prompts, 9 categories).
Usage: python scripts/data/generate_eval_dataset.py
"""
import json, random, os

random.seed(42)
evals = []

def ev(cat, prompt, expected, constraints, rubric=None):
    evals.append({
        "id": f"eval_{len(evals)+1:03d}",
        "category": cat,
        "prompt": prompt,
        "messages": [{"role": "user", "content": prompt}],
        "expected_behavior": expected,
        "hard_constraints": constraints,
        "scoring_rubric": rubric or {
            "instruction_following": "Follows the instruction exactly",
            "correctness": "Output is factually or logically correct",
            "format": "Output matches requested format",
            "concision": "No unnecessary verbosity",
            "hallucination": "No fabricated information"
        }
    })

# === instruction_following (17) ===
ev("instruction_following", "List 5 prime numbers. Output only the numbers, one per line, with no explanation.", "Exactly 5 prime numbers, one per line", ["numbers only", "no explanation", "one per line"])
ev("instruction_following", "Convert 'hello world' to uppercase. Do not add any extra text.", "HELLO WORLD", ["exact output", "no extra text"])
ev("instruction_following", "Write a haiku about rain. Follow the 5-7-5 syllable structure exactly.", "Haiku with correct syllable count", ["5-7-5 structure", "about rain"])
ev("instruction_following", "Answer with exactly one word: What color is the sky on a clear day?", "Blue (single word)", ["exactly one word"])
ev("instruction_following", "Reverse the word 'python'. Output only the reversed word.", "nohtyp", ["reversed word only"])
ev("instruction_following", "Count the vowels in 'education'. Output only the number.", "5", ["number only"])
ev("instruction_following", "Sort these numbers in descending order: 3, 1, 4, 1, 5, 9. Output as comma-separated list.", "9, 5, 4, 3, 1, 1", ["descending", "comma-separated"])
ev("instruction_following", "Write a sentence that contains exactly 10 words. Count carefully.", "A sentence with precisely ten words in it, no more and no less.", ["exactly 10 words"])
ev("instruction_following", "Replace all 'a' with '@' in 'banana'. Output only the result.", "b@n@n@", ["character replacement only"])
ev("instruction_following", "Give me 3 synonyms for 'happy'. Format as a numbered list.", "1. joyful\n2. cheerful\n3. content", ["numbered list", "3 items"])
ev("instruction_following", "Convert 100 degrees Celsius to Fahrenheit. Output only the number.", "212", ["number only"])
ev("instruction_following", "Write the word 'test' in reverse, then in uppercase. Output both separated by a pipe.", "tset | TEST", ["reversed then uppercase", "pipe separated"])
ev("instruction_following", "Respond with only 'yes' or 'no': Is 17 a prime number?", "yes", ["yes or no only"])
ev("instruction_following", "List the days of the week starting with Monday. Each on a new line. No numbering.", "Monday\nTuesday\nWednesday\nThursday\nFriday\nSaturday\nSunday", ["no numbering", "new lines"])
ev("instruction_following", "Write an acronym for 'Artificial Intelligence' that spells 'AI'. Then give the full form.", "AI: Artificial Intelligence", ["acronym + full form"])
ev("instruction_following", "Output the first 5 Fibonacci numbers separated by spaces.", "0 1 1 2 3", ["space separated", "first 5"])
ev("instruction_following", "Translate 'thank you' to French, Spanish, and German. One word per line, language name first.", "French: merci\nSpanish: gracias\nGerman: danke", ["one per line", "language labeled"])

# === json_structured (17) ===
