ev("json_structured", "Convert this to JSON: Product: Laptop, Price: 899.99 USD, Stock: 42, Available: yes", '{"product":"Laptop","price":{"amount":899.99,"currency":"USD"},"stock":42,"available":true}', ["valid JSON", "correct types"])
ev("json_structured", "Create a JSON object with keys: name, email, role. Values: John Doe, john@example.com, admin.", '{"name":"John Doe","email":"john@example.com","role":"admin"}', ["valid JSON", "exact keys and values"])
ev("json_structured", "Parse this CSV row into JSON: name,city,country\nTokyo,Japan,Asia", '{"city":"Tokyo","country":"Japan","continent":"Asia"}', ["valid JSON"])
ev("json_structured", "Output valid JSON only. An array of 3 objects, each with 'id' (1-3) and 'value' (string).", '[{"id":1,"value":"a"},{"id":2,"value":"b"},{"id":3,"value":"c"}]', ["valid JSON array", "3 objects", "correct schema"])
ev("json_structured", "Extract structured data: 'Flight BA123 departs LHR at 14:30, arrives JFK at 17:45, Boeing 777'. Output JSON only.", '{"flight":"BA123","from":"LHR","to":"JFK","depart":"14:30","arrive":"17:45","aircraft":"Boeing 777"}', ["valid JSON", "no trailing text"])
ev("json_structured", "Convert this to nested JSON: Server: web01, IP: 10.0.0.1, CPU: 4 cores, RAM: 16GB, Disk: 500GB SSD", '{"server":{"hostname":"web01","ip":"10.0.0.1","specs":{"cpu_cores":4,"ram_gb":16,"disk":{"size_gb":500,"type":"SSD"}}}}', ["valid JSON", "preserve nesting"])
ev("json_structured", "Create a JSON schema for a book with: title (string, required), author (string, required), isbn (string), pages (integer, min 1).", '{"type":"object","properties":{"title":{"type":"string"},"author":{"type":"string"},"isbn":{"type":"string"},"pages":{"type":"integer","minimum":1}},"required":["title","author"]}', ["valid JSON schema", "correct constraints"])
ev("json_structured", "Parse: 'Order #4521: 3x Widget A ($12.50 each), 1x Widget B ($45.00). Total: $82.50.' Output JSON.", '{"order":4521,"items":[{"name":"Widget A","qty":3,"unit_price":12.50,"subtotal":37.50},{"name":"Widget B","qty":1,"unit_price":45.00,"subtotal":45.00}],"total":82.50}', ["valid JSON", "correct math"])
ev("json_structured", "Output only valid JSON: a configuration object with database host, port, name, and credentials (user, password).", '{"database":{"host":"localhost","port":5432,"name":"mydb","credentials":{"user":"admin","password":"secret"}}}', ["valid JSON only", "no commentary"])
ev("json_structured", "Extract: 'Temperature 72F, Humidity 45%, Wind 12mph NW, Pressure 1013hPa' into JSON.", '{"temperature":{"value":72,"unit":"F"},"humidity_pct":45,"wind":{"speed_mph":12,"direction":"NW"},"pressure_hpa":1013}', ["valid JSON", "structured values"])
ev("json_structured", "Convert this table to JSON array:\nID | Name | Score\n1 | Alice | 95\n2 | Bob | 87\n3 | Carol | 92", '[{"id":1,"name":"Alice","score":95},{"id":2,"name":"Bob","score":87},{"id":3,"name":"Carol","score":92}]', ["valid JSON array", "all rows", "correct types"])
ev("json_structured", "Create a JSON response for a REST API: 200 OK, body has 'status', 'data' (user object), 'timestamp'.", '{"status":200,"data":{"id":1,"name":"User"},"timestamp":"2026-01-01T00:00:00Z"}', ["valid JSON", "REST structure"])
ev("json_structured", "Extract entities: 'Dr. Sarah Mitchell, PhD from MIT, works at Google DeepMind since 2019, London office.' JSON only.", '{"name":"Dr. Sarah Mitchell","education":{"degree":"PhD","institution":"MIT"},"employer":"Google DeepMind","start_year":2019,"office":"London"}', ["valid JSON", "all entities"])
ev("json_structured", "Parse semicolon-separated data: name=App;version=2.1;author=Bilawal;license=MIT into JSON.", '{"name":"App","version":"2.1","author":"Bilawal","license":"MIT"}', ["valid JSON", "correct parsing"])
ev("json_structured", "Output the following as compact JSON (no whitespace): A list of 3 colors with hex codes.", '[{"color":"red","hex":"#FF0000"},{"color":"green","hex":"#00FF00"},{"color":"blue","hex":"#0000FF"}]', ["compact JSON", "no whitespace"])
ev("json_structured", "Extract: 'Meeting at 3pm in Room 4B, attendees: Alice, Bob, Carol. Topic: Q4 budget review. Duration: 1 hour.'", '{"meeting":{"time":"15:00","location":"Room 4B","attendees":["Alice","Bob","Carol"],"topic":"Q4 budget review","duration":"1 hour"}}', ["valid JSON", "all fields"])

