ev("concision_antislip", "What does a proxy server do? Maximum 2 sentences.", "A proxy sits between you and the internet, forwarding your requests. It can hide your IP, cache content, or block access.", ["max 2 sentences", "direct"])
ev("concision_antislip", "Explain git rebase vs merge in under 30 words.", "Merge creates a merge commit combining branches. Rebase replays your commits on top of another branch, creating linear history.", ["under 30 words", "no filler"])
ev("concision_antislip", "What is a VPN? One sentence only.", "A VPN encrypts your internet connection and routes it through a remote server, hiding your real IP and location.", ["one sentence"])
